_ONE_DAY_IN_SECONDS = 60 * 60 * 24

class AuthServicer(auth_pb2_grpc.AuthServicer):
    def Login(self, request, context):
        print(f"AuthServicer: Login request for user: {request.username}")
        if request.username == "testuser" and request.password == "password123":
            return auth_pb2.LoginResponse(
                success=True,
                token="mock_auth_token_123",
                message="Login successful"
            )
        return auth_pb2.LoginResponse(
            success=False,
            token="",
            message="Invalid credentials"
        )

    def Register(self, request, context):
        print(f"AuthServicer: Register request for user: {request.username}, email: {request.email}")
        # In a real app, you'd save this to a DB
        if request.username == "existinguser":
            return auth_pb2.RegisterResponse(
                success=False,
                message="Username already taken"
            )
        return auth_pb2.RegisterResponse(
            success=True,
            message="Registration successful"
        )

class DataServicer(data_pb2_grpc.DataServicer):
    def GetUserProfile(self, request, context):
        print(f"DataServicer: GetUserProfile request for user_id: {request.user_id}")
        # Mock authorization check
        if request.auth_token != "mock_auth_token_123":
            context.set_code(grpc.StatusCode.UNAUTHENTICATED)
            context.set_details("Invalid authentication token")
